const data = $('Get Referral Leaderboard').first().json;

const prompt = `Write a referral leaderboard post for Twitter and Telegram. Here's the top 10 referrers:

${JSON.stringify(data, null, 2)}

Make it fun and competitive. Include #Bitcoin #BTC. Encourage others to share their link via /referral. Max 270 chars for tweet. Also generate a longer Telegram version (max 1000 chars) with Markdown formatting.

Return JSON: {"tweet": "...", "telegram": "..."}`;

return [{ json: { prompt, data } }];

const response = $('Claude Generate').first().json;
const raw = response.content[0].text.trim();

// Try to parse JSON response for separate tweet/telegram text
let tweet, telegram;
try {
  const parsed = JSON.parse(raw);
  tweet = parsed.tweet;
  telegram = parsed.telegram;
} catch (e) {
  // If not JSON, use raw text for both
  tweet = raw.substring(0, 270);
  telegram = raw;
}

return [{ json: { tweet, telegram } }];

const tweet = $('Extract Text').first().json.tweet;
const now = new Date().toISOString();
console.log(`[${now}] Referral leaderboard posted: ${tweet.substring(0, 80)}...`);
return [{ json: { status: 'posted', timestamp: now, channel: 'twitter+telegram' } }];
